import React, { useState } from 'react';
import auth from '../services/auth';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const res = await auth.login(email, password);
    setLoading(false);
    if (res.ok) {
      window.location.href = '/';
    } else {
      setError(res.message || 'Login failed');
    }
  };

  return (
    <div
      className="login-page"
      style={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'var(--bg)'
      }}
    >
      <div
        className="login-card fade-in"
        style={{
          width: '100%',
          maxWidth: '420px'
        }}
      >
        <div className="login-logo">
          <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
            <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5" />
          </svg>
        </div>

        <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
          <h1 className="login-title">Admin Portal</h1>
          <p className="login-subtitle">Harari Saving & Credit Management</p>
        </div>

        {error && (
          <div
            className="fade-in"
            style={{
              padding: '0.875rem',
              background: 'rgba(244, 63, 94, 0.1)',
              border: '1px solid rgba(244, 63, 94, 0.2)',
              color: 'var(--danger)',
              borderRadius: '8px',
              marginBottom: '1.5rem',
              fontSize: '0.8125rem',
              fontWeight: 500,
              textAlign: 'center'
            }}
          >
            {error}
          </div>
        )}

        <form onSubmit={submit} style={{ display: 'grid', gap: '1.25rem' }}>
          <div className="input-group">
            <label className="label">Admin Email</label>
            <input
              className="input"
              type="email"
              placeholder="admin@harari.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
              required
            />
          </div>

          <div className="input-group">
            <label className="label">Password</label>
            <div style={{ position: 'relative' }}>
              <input
                className="input"
                type={showPassword ? 'text' : 'password'}
                placeholder="••••••••"
                value={password}
                onChange={e => setPassword(e.target.value)}
                required
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                style={{
                  position: 'absolute',
                  right: '0.75rem',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: 'var(--text-muted)',
                  cursor: 'pointer'
                }}
              >
                {showPassword ? '🙈' : '👁️'}
              </button>
            </div>
          </div>

          <button className="btn-login-cool" type="submit" disabled={loading}>
            {loading ? 'Authenticating...' : 'Sign In to Dashboard'}
          </button>
        </form>

        <div
          style={{
            marginTop: '2.5rem',
            textAlign: 'center',
            borderTop: '1px solid var(--border)',
            paddingTop: '1.5rem'
          }}
        >
          <p
            style={{
              margin: 0,
              color: 'var(--text-muted)',
              fontSize: '0.75rem',
              fontWeight: 600,
              letterSpacing: '0.025em'
            }}
          >
            SECURE ENTERPRISE ACCESS
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
